const rawItems = $input.all().map(item => item.json || {});

function toTimestamp(value) {
  if (!value) return 0;
  const ts = new Date(value).getTime();
  return Number.isFinite(ts) ? ts : 0;
}

function asBool(value) {
  return value === true || value === 'true' || value === 1 || value === '1';
}

// убираем пустые placeholder-items вроде {}
const tickets = rawItems.filter(t => {
  const ticketId = String(t.ticket_id || '').trim();
  return ticketId !== '';
});

if (tickets.length === 0) {
  return [
    {
      json: {
        active_tickets_count: 0,
        has_multiple_active: false,

        latest_ticket_id: '',
        latest_status: '',
        latest_problem_text: '',
        latest_user_lang: '',
        latest_it_reply_text: '',
        latest_pending_manager_request: '',
        latest_pending_user_action: '',
        latest_scenario_key: '',

        latest_has_screenshot: false,
        latest_screenshot_file_id: '',

        latest_details_website: '',
        latest_details_username: '',
        latest_details_password: '',
        latest_details_amount: '',
        latest_details_operation: '',
        latest_details_complete: false,

        active_tickets_summary: '',
        active_tickets: [],

        has_ticket_choice_checkpoint: false,
        choice_checkpoint_message_id: '',
      },
    },
  ];
}

// сортируем: самая свежая заявка первой
tickets.sort((a, b) => {
  const aTime = toTimestamp(a.updatedAt || a.created_at);
  const bTime = toTimestamp(b.updatedAt || b.created_at);
  return bTime - aTime;
});

const latest = tickets[0];

const activeTicketsSummary = tickets
  .map((t, index) => {
    const parts = [
      `${index + 1}) ${t.ticket_id || 'no_ticket'}`,
      t.scenario_key || 'unknown_scenario',
      t.status || 'unknown_status',
    ];

    if (t.pending_manager_request) {
      parts.push(`manager_request: ${String(t.pending_manager_request).trim()}`);
    }

    return parts.join(' | ');
  })
  .join('\n');

return [
  {
    json: {
      active_tickets_count: tickets.length,
      has_multiple_active: tickets.length > 1,

      latest_ticket_id: latest.ticket_id || '',
      latest_status: latest.status || '',
      latest_problem_text: latest.problem_text || '',
      latest_user_lang: latest.user_lang || '',
      latest_it_reply_text: latest.it_reply_text || '',
      latest_pending_manager_request: latest.pending_manager_request || '',
      latest_pending_user_action: latest.pending_user_action || '',
      latest_scenario_key: latest.scenario_key || '',

      latest_has_screenshot: asBool(latest.has_screenshot),
      latest_screenshot_file_id: latest.screenshot_file_id || '',

      latest_details_website: latest.details_website || '',
      latest_details_username: latest.details_username || '',
      latest_details_password: latest.details_password || '',
      latest_details_amount: latest.details_amount || '',
      latest_details_operation: latest.details_operation || '',
      latest_details_complete: asBool(latest.details_complete),

      active_tickets_summary: activeTicketsSummary,
      active_tickets: tickets,

      has_ticket_choice_checkpoint: tickets.some(
        t => String(t.last_bot_prompt_kind || '').trim() === 'awaiting_ticket_choice'
      ),

      choice_checkpoint_message_id: tickets
        .map(t => String(t.last_bot_message_id || '').trim())
        .filter(Boolean)[0] || '',
    },
  },
];

