const text = (($json.user_message || '') + '').trim();
const low = text.toLowerCase();

const explicitTicketId = (text.match(/\bT-\d+-\d+\b/i) || [])[0] || '';
const explicitChoiceIndex = (/^\s*([1-9]\d*)\s*$/.exec(text) || [])[1] || '';

const flagConfirmNewYes = /^(да\s*,?\s*нов(ая|ый)?|yes\s*,?\s*new|yes|да)$/i.test(low);
const flagConfirmNewNo = /^(нет|no)$/i.test(low);

const flagAskHuman =
  /(оператор|человек|менеджер|support|human|agent|operator)/i.test(text);

const flagAggressive =
  /(идиот|тупой|урод|сука|бляд|дебил|нахуй|fuck you|stupid|idiot)/i.test(low);

const flagNewProblem =
  /(нов(ая|ый)\s+проблем|друг(ая|ой)\s+проблем|another problem|new problem|ещ[её]\s+одна\s+проблем)/i.test(low);

const flagSameProblem =
  /(по этой заявке|по текущей|это не новая|не новая|same problem|current ticket)/i.test(low);

const flagShortFragment = text.length > 0 && text.length <= 20;

const flagLikelySingleField =
  !explicitTicketId &&
  !explicitChoiceIndex &&
  !flagAskHuman &&
  !flagNewProblem &&
  (
    /^[^\s]+\.[a-z]{2,}$/i.test(text) ||     // domain
    /^[A-Za-z0-9_\-]{3,}$/.test(text) ||     // login/password like
    /^\d+([.,]\d+)?$/.test(text)             // amount
  );

return [
  {
    json: {
      ...$json,
      explicit_ticket_id: explicitTicketId,
      explicit_choice_index: explicitChoiceIndex,
      flag_confirm_new_yes: flagConfirmNewYes,
      flag_confirm_new_no: flagConfirmNewNo,
      flag_ask_human: flagAskHuman,
      flag_aggressive: flagAggressive,
      flag_new_problem: flagNewProblem,
      flag_same_problem: flagSameProblem,
      flag_short_fragment: flagShortFragment,
      flag_likely_single_field: flagLikelySingleField
    }
  }
];

const tickets = JSON.parse($json.active_tickets_json || '[]');
const activeCount = Number($json.active_tickets_count || 0);

let preselected_target_action = 'undecided';
let preselected_target_ticket_id = '';
let preselected_target_source = 'none';

const hasPrivateReplyId = !!String($json.reply_to_message_id_private || '').trim();

const hasStrongContinuation =
  (hasPrivateReplyId && $json.reply_ticket_found === true) ||
  !!$json.pending_user_action_current ||
  !!$json.manager_request ||
  $json.flag_short_fragment === true ||
  $json.flag_likely_single_field === true ||
  $json.flag_same_problem === true ||
  $json.flag_confirm_new_no === true;

const norm = (v) => String(v || '').toLowerCase().trim();
const textNorm = norm($json.user_message);

const matchedByWebsiteLogin = tickets.filter((t) => {
  const w = norm(t.details_website);
  const u = norm(t.details_username);
  if (!w || !u) return false;
  return textNorm.includes(w) && textNorm.includes(u);
});

if ($json.reply_ticket_found === true && hasPrivateReplyId && $json.reply_ticket_id) {
  preselected_target_action = 'use_existing';
  preselected_target_ticket_id = $json.reply_ticket_id;
  preselected_target_source = 'reply_chain';

} else if ($json.explicit_ticket_id) {
  const found = tickets.find((t) => (t.ticket_id || '') === $json.explicit_ticket_id);
  if (found) {
    preselected_target_action = 'use_existing';
    preselected_target_ticket_id = found.ticket_id || '';
    preselected_target_source = 'explicit_ticket_id';
  }

} else if (
  (
    $json.has_ticket_choice_checkpoint === true ||
    $json.pending_user_action_current === 'awaiting_ticket_choice'
  ) &&
  $json.explicit_choice_index
) {
  const idx = Number($json.explicit_choice_index) - 1;
  if (tickets[idx]?.ticket_id) {
    preselected_target_action = 'use_existing';
    preselected_target_ticket_id = tickets[idx].ticket_id || '';
    preselected_target_source = 'user_choice';
  }

} else if (matchedByWebsiteLogin.length === 1 && !$json.flag_new_problem) {
  preselected_target_action = 'use_existing';
  preselected_target_ticket_id = matchedByWebsiteLogin[0].ticket_id || '';
  preselected_target_source = 'field_match';

} else if (activeCount === 0) {
  preselected_target_action = 'create_new';
  preselected_target_ticket_id = '';
  preselected_target_source = 'new_ticket';

} else if (activeCount === 1 && hasStrongContinuation && !$json.flag_new_problem) {
  preselected_target_action = 'use_existing';
  preselected_target_ticket_id = $json.ticket_id_current || tickets[0]?.ticket_id || '';
  preselected_target_source = 'single_active';

} else if (activeCount > 1) {
  preselected_target_action = 'ask_choose_ticket';
  preselected_target_ticket_id = '';
  preselected_target_source = 'multiple_active_ambiguous';
}

return [
  {
    json: {
      ...$json,
      preselected_target_action,
      preselected_target_ticket_id,
      preselected_target_source
    }
  }
];

