const items = $input.all();

function sanitizeTelegramHtmlText(value) {
  let text = String(value ?? '');

  // 1) Нормализуем переводы строк
  text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  // 2) Удаляем опасные управляющие символы, кроме \n и \t
  text = text.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g, '');

  // 3) Удаляем zero-width / BOM
  text = text.replace(/[\u200B-\u200D\uFEFF]/g, '');

  // 4) Экранируем HTML-опасные символы
  text = text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

  // 5) Убираем пробелы в конце строк
  text = text.replace(/[ \t]+$/gm, '');

  // 6) Сжимаем слишком много пустых строк
  text = text.replace(/\n{3,}/g, '\n\n');

  // 7) Финальная обрезка
  text = text.trim();

  return text;
}

return items.map(item => {
  const json = item.json || {};
  const original = json.it_text || '';
  const safe = sanitizeTelegramHtmlText(original);

  return {
    json: {
      ...json,
      it_text_original: original,
      it_text_safe: safe,
      telegram_sanitize_meta: {
        changed: original !== safe,
        original_length: original.length,
        safe_length: safe.length,
        mode: 'html_safe',
      }
    }
  };
});

